import { useCallback, useState } from "react";
import type { UsersData, ProductData } from "../../utils/dataTypesUtils";
import { host, httpMethod } from "../../utils/utils";

export function useUsers(channel: string = "channel-a") {
  const [data, setData] = useState<UsersData | null>(null);
  const [products, setProducts] = useState<ProductData[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  const fetchUsers = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await fetch(`${host}/traders/${channel}`, {
        method: httpMethod.GET,
        headers: { "Content-Type": "application/json" },
      });

      if (response.ok) {
        const responseData = await response.json();
        let parsedUsers = [];
        if (responseData.Users) {
          try {
            parsedUsers = JSON.parse(responseData.Users);
            if (!Array.isArray(parsedUsers)) {
              parsedUsers = [];
            }
          } catch (parseError) {
            console.warn(
              `Failed to parse traders, defaulting to empty array`,
              parseError
            );
            parsedUsers = [];
          }
        }

        const parsedData = {
          ...responseData,
          Users: parsedUsers,
        };
        setData(parsedData);
      } else {
        const errorData = await response.json();
        setError(errorData.Message || "Failed to fetch traders");
      }
    } catch (err) {
      setError(
        `Error connecting to server: ${
          err instanceof Error ? err.message : String(err)
        }`
      );
    } finally {
      setLoading(false);
    }
  }, [channel]);

  const deleteUser = useCallback(
    async (traderId: string) => {
      try {
        const response = await fetch(`${host}/traders/${channel}/${traderId}`, {
          method: httpMethod.DELETE,
          headers: { "Content-Type": "application/json" },
        });

        if (response.ok) {
          await fetchUsers();
          return { success: true };
        } else {
          const errorData = await response.json();
          const errorMsg = errorData.Message || "Failed to delete trader";
          setError(errorMsg);
          return { success: false, error: errorMsg };
        }
      } catch (err) {
        const errorMsg = `Error deleting trader: ${
          err instanceof Error ? err.message : String(err)
        }`;
        setError(errorMsg);
        return { success: false, error: errorMsg };
      }
    },
    [channel, fetchUsers]
  );

  const fetchProductsByIds = useCallback(
    async (productIds: string[]) => {
      if (!productIds || productIds.length === 0) {
        setProducts([]);
        return;
      }

      setLoading(true);
      setError(null);

      try {
        const response = await fetch(
          `http://localhost:8080/products/${channel}/by-ids`,
          {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ productIds }),
          }
        );

        if (response.ok) {
          const responseData = await response.json();
          let parsedProducts = [];

          if (responseData.Products) {
            try {
              parsedProducts = JSON.parse(responseData.Products);
              if (!Array.isArray(parsedProducts)) {
                parsedProducts = [];
              }
            } catch (parseError) {
              console.warn("Failed to parse products", parseError);
              parsedProducts = [];
            }
          }

          setProducts(parsedProducts);
        } else {
          const errorData = await response.json();
          setError(errorData.error || "Failed to fetch products");
          setProducts([]);
        }
      } catch (err) {
        setError(
          `Error fetching products: ${
            err instanceof Error ? err.message : String(err)
          }`
        );
        setProducts([]);
      } finally {
        setLoading(false);
      }
    },
    [channel]
  );

  const clearProducts = useCallback(() => {
    setProducts([]);
    setError(null);
  }, []);

  return {
    traders: data?.Users || [],
    products: products,
    loading,
    error,
    fetchUsers,
    fetchProductsByIds,
    clearProducts,
    deleteUser,
  };
}
